#!/usr/bin/env dotnet
#:property PublishAot=false

// Find the earliest Friday the 13th in the proleptic Gregorian calendar (from 0001-01-01)
// and count how many occur in a full 400-year cycle.

// --- Earliest Friday the 13th ---
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// --- Count in a full 400-year cycle (0001-01-01 to 0400-12-31) ---
int count = 0;
List<DateTime> first10 = [];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            count++;
            if (first10.Count < 10)
                first10.Add(d);
        }
    }
}

Console.WriteLine($"\nFriday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

Console.WriteLine("\nFirst 10 occurrences:");
foreach (var d in first10)
    Console.WriteLine($"  {d:yyyy-MM-dd}");

// --- Bonus: distribution by day of week for the 13th ---
Console.WriteLine("\nDay-of-week distribution for the 13th (400-year cycle):");
var dayCounts = new int[7];
for (int year = 1; year <= 400; year++)
    for (int month = 1; month <= 12; month++)
        dayCounts[(int)new DateTime(year, month, 13).DayOfWeek]++;

foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {dayCounts[(int)dow],4}");

